import React, { useEffect } from 'react';
import { Linking } from 'react-native';
import { NavigationContainer, createNavigationContainerRef } from '@react-navigation/native';

export const navigationRef = createNavigationContainerRef();

function navigateToDeepLink(url) {
  if (!url || !navigationRef.isReady()) return;

  const parsed = Linking.parse(url);
  const path = parsed.path || '';
  const segments = path.split('/').filter(Boolean);

  if (segments[0] === 'profile' && segments[1]) {
    navigationRef.navigate('Profile', { userId: segments[1] });
    return;
  }

  if (segments[0] === 'payment' && segments[1] === 'confirm') {
    navigationRef.navigate('PaymentConfirm');
    return;
  }

  navigationRef.navigate('Home');
}

export function useDeepLinkHandler() {
  useEffect(() => {
    const handleUrl = ({ url }) => navigateToDeepLink(url);

    Linking.getInitialURL().then((url) => {
      if (url) {
        setTimeout(() => navigateToDeepLink(url), 0);
      }
    });

    const subscription = Linking.addEventListener('url', handleUrl);

    return () => {
      subscription.remove();
    };
  }, []);
}

export default function AppNavigator({ children }) {
  useDeepLinkHandler();

  return (
    <NavigationContainer ref={navigationRef}>
      {children}
    </NavigationContainer>
  );
}

export const linking = {
  prefixes: ['myapp://'],
  config: {
    screens: {
      Home: '',
      Profile: 'profile/:userId',
      PaymentConfirm: 'payment/confirm',
    },
  },
};

export function buildDeepLinkNavigation(screenName, params = {}) {
  if (!navigationRef.isReady()) return;

  switch (screenName) {
    case 'Profile':
      if (params.userId) {
        navigationRef.navigate('Profile', { userId: params.userId });
      }
      break;
    case 'PaymentConfirm':
      navigationRef.navigate('PaymentConfirm');
      break;
    default:
      navigationRef.navigate('Home');
  }
}